text:
&-content {
	.content-style();
	&-data {
		display: flex;
		width: 100%;
		box-sizing: border-box;
		padding: 64px 80px;
		font-size: 1rem;
		flex-wrap: wrap;
		transition: all 0.4s ease-in-out;
		h2{
			display: inline-block;
			width: 100%;
			margin-bottom: 40px;
			color: #424242;
			font-size: 1.7rem;
		}
		a {
			display: flex;
			align-items: center;
			text-decoration: none;
			margin-right: 20px;
			&>span {
				background-color: rgba(96,125,139,.05);
				line-height: 2.4;
				transition: all .15s;
				padding: 0 12px;
				margin-bottom: 15px;
				border-radius: 6px;
				position: relative;
				top: 0;
				color: #43576B;
				font-weight: 400;
				font-size: 16px;
				&:hover {
					top: -2px;
					background-color: #607d8b;
					color: #ffffff;
					transition: all .3s ease-in-out;
				}
				&>i {
					text-align: center;
					color: #F56C6C;
					font-size: 15px;
					font-weight: 500;
				}
			}
		}
	}
}

&.btn-material {
    background-color: transparent!important;
    border: none!important;
    .border-radius(2px);

    > button {
        .btn-material;
    }

    button.ui-button.ui-splitbutton-menubutton  {
        border: none;
        .btn-interactions(@btn-background-color);
    }

    &.btn-default > button {
        .btn-interactions(@btn-background-color);
        color: rgba(0,0,0,.87)!important;
        span.ui-icon {
            color: rgba(0,0,0,.87);
        }
    }

    &.btn-success > button {
        .btn-interactions(@btn-background-color);
        color: @green!important;
        span.ui-icon {
            color: green;
        }
    }

    &.btn-primary > button {
        .btn-interactions(@btn-background-color);
        color: @light-blue!important;
        span.ui-icon {
            color: @light-blue;
        }
    }

    &.btn-teal > button {
      .btn-interactions(@btn-background-color);
      color: @admin-teal !important;

      span.ui-icon {
        color: @admin-teal;
      }

    }
}

body .ui-tabs.ui-tabs-top .ui-tabs-nav.ui-widget-header li.ui-state-active {
    border-top: 3px solid @tabview-border-top-color;

    .tabviewSolid(@tabview-border-top-color, #fff);

    &.box-default {
        border-top: 3px solid @gray-lte;
        .tabviewSolid(@gray-lte, #444);
    }

    &.box-danger {
        border-top: 3px solid @red;
        .tabviewSolid(@red, #fff);
    }

    &.box-fatal {
        border-top: 3px solid @dark-red;
        .tabviewSolid(@dark-red, #fff);
    }

    &.box-warning {
        border-top: 3px solid @yellow;
        .tabviewSolid(@yellow, #fff);
    }

    &.box-success {
        border-top: 3px solid @green;
        .tabviewSolid(@green, #fff);
    }

    &.box-info {
        border-top: 3px solid @aqua;
        .tabviewSolid(@aqua, #fff);
    }

    &.box-teal {
        border-top: 3px solid @admin-teal;
        .tabviewSolid(@admin-teal, #fff);
    }

    &.no-color {
        border-top: 1px solid #d2d6de;
        .tabviewSolid(#f6f7f9, @admin-text-color);
    }
}

input[type="checkbox"] {
  position: relative;
  width: 14px;
  height: 14px;
  vertical-align: middle;
  background-color: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 2px;
  box-shadow: none;
  outline: none;

  &:checked {
    // background-color: @checkbox-bg;
    // border-color: @checkbox-bg;

    &:after {
      position: absolute;
      left: 0;
      top: 2px;
      line-height: 10px;
      background-color: transparent;
      content: '\00ac';
      font-family: arial;
      // color: #fff;
      color: @checkbox-bg;
      font-size: 12px;
      font-weight: bolder;
      border-radius: 2px;
      text-align: center;
      transform: rotate(135deg) translateX(-50%);
    }
  }

  &[disabled], &[disabled]:checked {
    background-color: #f2f2f2;
    border-color: #e6e6e6;
    color: #ccc;
    cursor: not-allowed;
    &:after {
      background-color: #f2f2f2;
      color: #ccc;
    }
  }
}

> li {
  width: 100%; // disable block-grid

  &.am-parent {
    > a {
      position: relative;
      &::before {
        content: @fa-var-plus;
        position: absolute;
        right: 1rem;
        top: 1.4rem;
      }
    }

    // active
    &.am-open {
      > a {
        background-color: @menu-nav-top-link-active-bg;
        border-bottom: none;
        color: @menu-nav-top-link-active-color;

        &:before {
          content: @fa-var-minus;
        }

        &:after {
          content: "";
          .caret-down(8px, @menu-nav-top-link-active-bg);
          position: absolute;
          top: 100%;
          left: 50%;
          margin-left: -4px;
        }
      }
    }
  }

  > a {
    border-bottom: 1px solid @menu-nav-border-color;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.05);
    background-color: @menu-nav-top-link-bg;
    color: @menu-nav-top-link-color;
    height: @menu-nav-link-height;
    line-height: @menu-nav-link-height;
    padding: 0;
    text-indent: 10px;
  }
}

&-item {
  display: flex;
  align-items: center;
  box-sizing: border-box;
  padding: 16px 12px;
  position: relative;
  cursor: pointer;
  background-color: var(--background-color);
  overflow: visible;

  &-highlight {
    position: absolute;
    height: 100%;
    width: 2px;
    left: -12px;
    top: 0;
    background: var(--adm-color-primary);
    border-radius: 2px;
  }

  &-active {
    color: var(--adm-color-primary);
    background-color: var(--adm-color-background);
    position: relative;
  }

  &-corner {
    width: var(--item-border-radius);
    height: var(--item-border-radius);
    position: absolute;
    z-index: 100;
    right: 0;
    user-select: none;
    pointer-events: none;
    &-top {
      top: 0;
      transform: rotate(-90deg);
    }
    &-bottom {
      bottom: 0;
    }
  }

  &-disabled {
    cursor: not-allowed;
    .@{class-prefix-side-bar}-item-title {
      opacity: 0.4;
    }
  }
}

@media screen and (max-width: 450px) {
  // 影响移动端所有页面
  #root .__dumi-default-navbar {
    padding: 0 58px;
  }

  .__dumi-default-search-input {
    display: none;
  }

  // 影响移动端首页
  .__dumi-default-layout[data-route='/'].__dumi-default-layout[data-gapless='true'] {
    .__dumi-default-navbar {
      position: sticky;
      top: 0;
      background-color: #1677ff;
      opacity: 0.95;
      box-shadow: 0px 1px 1px 0px #eeeeee40 !important;
    }

    .__dumi-default-navbar-toggle {
      width: 16px;
      height: 16px;
      background: url(https://gw.alipayobjects.com/zos/bmw-prod/2a780b32-f3dd-4e13-8c27-2369d898bd76.svg)
        no-repeat center / cover;
    }

    .__dumi-default-menu {
      background-color: #1677ff;
      opacity: 0.95;

      .__dumi-default-menu-inner .__dumi-default-menu-mobile-area {
        border-bottom: none;
      }

      a {
        color: #fff !important;
      }
    }

    .__dumi-default-menu[data-mode='site']::after {
      transform: scaleX(0.2);
    }
  }
}

&-button {
  padding: 8px 16px;
  border-radius: 40px;
  font-size: 14px;
  border: 1px solid @text-color-light;
  transition: background @animate-duration @ease-out, box-shadow @animate-duration @ease-out;
  color: @text-color-light;
  display: inline-block;
  & i {
    width: 16px;
    margin-left: 7px;
    background: url(https://zos.alipayobjects.com/rmsportal/dgqoflLasHqTmNM.svg) center no-repeat;
    background-size: contain;
    filter: brightness(1);
    height: 16px;
    display: inline-block;
    vertical-align: sub;
    text-transform: none;
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    line-height: 1;
    transition: filter @animate-duration @ease-out;
  }

  &:hover {
    background: fade(@text-color-light, 15);
    box-shadow: 0 0 6px fade(@text-color-light, 35);
  }
  &.template {
    margin-left: 10px;
    & i {
      background: url(https://zos.alipayobjects.com/rmsportal/IlXQOcjKCQNSbPdDamWL.svg) center no-repeat;
      background-size: cover;
    }
  }
}

& when (@listing-grid-item-actions__position = absolute) {
    .listing-grid-item-actions-absolute();

    & when (@critical) {
        @media @media-hover-none {
            .product-item-details {
                .product-item-actions {
                    opacity: 1;
                    pointer-events: all;
                    .lib-css(transform, @listing-grid-item-actions__absolute__visible__transform);
                }
            }
        }
    }

    & when not (@critical) {
        @media @media-hover {
            &:hover,
            &:has(:focus-visible) {
                .product-item-details {
                    .product-item-actions {
                        opacity: 1;
                        pointer-events: all;
                        .lib-css(transform, @listing-grid-item-actions__absolute__visible__transform);
                    }
                }
            }
        }
    }
}

[type=range] {
    margin: 0;
    padding: 0;
    width: 100%;
    height: @4;
    background-color: transparent;
    appearance: none;

    &::-webkit-slider-runnable-track {
        width: 100%;
        height: @1;
        color: transparent;
        cursor: pointer;
        background-color: var(--subtle-color);
        border-color: transparent;
        border-radius: 9999px;
    }

    &::-moz-range-track {
        width: 100%;
        height: @1;
        color: transparent;
        cursor: pointer;
        background-color: var(--subtle-color);
        border-color: transparent;
        border-radius: 9999px;
    }

    &::-webkit-slider-thumb {
        width: @4;
        height: @4;
        margin-top: -@1-5;
        background-color: var(--checkbox-color, var(--color-brand));
        border: 0;
        border-radius: 9999px;
        -webkit-appearance: none;
        appearance: none;
    }

    &::-moz-range-thumb {
        width: @4;
        height: @4;
        margin-top: -@1-5;
        background-color: var(--checkbox-color, var(--color-brand));
        border: 0;
        border-radius: 9999px;
        appearance: none;
    }
}

&-item {
    &.selected-item {
        border-color: var(--color-brand);
        &::after {
            color: var(--color-brand);
            .breeze-icon(@icon-check);
            position: absolute;
            bottom: 0;
            .right(0);
            content: '';
            width: @8;
            height: @11;
            padding: @2;
        }
    }

    .action {
        &:extend(.transition all);
    }

    .edit-address-link {
        &:extend(.breeze-button-reset all);
        .right(@2);
        top: @2;
        width: @6;
        height: @6;
        opacity: .6;
        background: var(--base-bg);

        &::before {
            .breeze-icon(@icon-pencil, @5);
            content: '';
            width: @6;
            height: @6;
            display: block;
            color: inherit !important;
        }
        span {
            &:extend(.breeze-sr-only);
        }
    }

    &:hover {
        .action-select-shipping-item {
            opacity: 1;
        }
    }
}

& when (@critical) {
    // enable for both hover and hover-none devices
    & when not (@_hover-none-visible-height = false) {
        .listing-reveal-on-hover-base(@_aspect-ratio);
    }

    @media @media-hover {
        // enable for hover devices only
        & when (@_hover-none-visible-height = false) {
            .listing-reveal-on-hover-base(@_aspect-ratio);
        }
        .listing-reveal-on-hover-visible-height(@_aspect-ratio, @_visible-height);
    }

    // enable for hover-none devices
    @media @media-hover-none {
        & when (@listing-grid-item-actions-secondary__position = absolute) {
            .product-item-inner,
            .actions-secondary {
                opacity: 1;
                pointer-events: all;
            }
        }
        & when not (@_hover-none-visible-height = false) {
            .actions-primary {
                opacity: 0;
                pointer-events: none;
            }
            .listing-reveal-on-hover-visible-height(@_aspect-ratio, @_hover-none-visible-height);
        }
    }
}

nav[role="navigation"] {
  .navbar-header .navbar-toggle {
    border-color: @accent;
    .icon-bar {
      background-color: @accent;
    }
  }

  .navbar-logo > img {
    @svg: escape(
      '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 27 30"><path fill="@{mauve}" d="M13 1 1 8v14l12 7z"/><path fill="@{peach}" d="m14 1 12 7v14l-12 7z"/></svg>'
    );
    content: url("data:image/svg+xml,@{svg}");
  }

  #side-nav {
    background-color: @mantle;
    a,
    a:visited {
      color: @blue;
      &:hover {
        color: @sky;
      }
    }

    .search-bar input {
      background-color: @surface0;
      color: @text;
      &:focus {
        box-shadow: inset 1px 2px 4px @surface1;
        ~ button {
          box-shadow: inset -3px 2px 4px @surface2;
        }
      }
      ~ button {
        background-color: @surface1;
        color: @text;
      }
    }

    .mobile-nav-fix {
      background-color: transparent;
    }
  }

  #side-nav-overlay {
    background-color: @crust;
  }
}

ul.sidebar {
    position: fixed;
    left: 0px;
    width: @sidebarWidth;
    height: calc(100vh - @mainPushDown);
    top: @mainTop;
    background: #5a6169;
    border-right: @sidebarBorder solid #EEE;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    padding-top: 0.5rem;
    padding-bottom: 0.5rem;
    box-shadow: -200px -141px 30px -200px rgba(0,0,0,0.39) inset;
    -webkit-box-shadow: -200px -141px 30px -200px rgba(0,0,0,0.39) inset;
    -moz-box-shadow: -200px -141px 30px -200px rgba(0,0,0,0.39) inset;

    li {
        padding: 0.3rem;
        font-size: 2.5rem;
        margin: 0.3rem;
        margin-bottom: 1rem;
        border-radius: 1rem;
        display: flex;
        align-items: center;
        justify-content: center;
        height: 3rem;
        color: #AAA;
        text-shadow: 0px 1px 0px rgba(255,255,255,.3), 0px -1px 0px rgba(0,0,0,.7);

        &:nth-child(4) {
            margin-top: auto;
        }

        &.active {
            color: #5fbff9;
        }

        &:not(.active):hover {
            color: #CCC;
            border-color: #EEE;
        }
    }
}

@media (-moz-touch-enabled), (pointer: coarse) {
    .ui.dropdown .scrollhint.menu:not(.hidden)::before {
        animation: scrollhint @scrollhintDuration @scrollhintEasing @scrollhintIteration;
        content: "";
        z-index: @scrollhintZIndex;
        display: block;
        position: absolute;
        opacity: 0;
        right: @scrollhintOffsetRight;
        top: 0;
        height: 100%;
        border-right: @scrollhintRightBorder;
        border-left: @scrollhintLeftBorder;
        border-image: linear-gradient(to bottom, @scrollhintStartColor, @scrollhintEndColor) 1 100%;
    }

    .ui.inverted.dropdown .scrollhint.menu:not(.hidden)::before {
        border-image: linear-gradient(to bottom, @invertedScrollhintStartColor, @invertedScrollhintEndColor) 1 100%;
    }

    @keyframes scrollhint {
        0% {
            opacity: 1;
            top: 100%;
        }
        100% {
            opacity: 0;
            top: 0;
        }
    }
}

& when (@variationButtonBasic) {
    .ui.spaced.basic.buttons {
        border: none;
        & .button {
            border: @basicGroupBorder;
            &.basic {
                border: none;
            }
        }
    }
    & when (@variationButtonVertical) {
        .ui.spaced.basic.vertical.buttons .button:first-child {
            border-top: @basicGroupBorder;
        }
    }
    & when (@variationButtonWrapping) {
        .ui.spaced.basic.wrapping.buttons .button@{notBasic} {
            border-top: @basicGroupBorder;
            border-right: @basicGroupBorder;
            &:first-child {
                border-left: @basicGroupBorder;
            }
        }
    }
    & when (@variationButtonInverted) {
        .ui.spaced.basic.inverted.buttons .basic.button {
            margin-bottom: e(%("calc(%d + %d)", @spacedMargin, @basicColoredBorderSize));
            margin-top: @basicColoredBorderSize;
        }
    }
}

& when (@variationSidebarRight) {
    & when (@variationSidebarThin) {
        .ui.visible.thin.right.sidebar ~ .fixed,
        .ui.visible.thin.right.sidebar ~ .pusher {
            transform: translate3d(-@thinWidth, 0, 0);
        }

        & when (@variationSidebarVeryThin) {
            .ui.visible[class*="very thin"].right.sidebar ~ .fixed,
            .ui.visible[class*="very thin"].right.sidebar ~ .pusher {
                transform: translate3d(-@veryThinWidth, 0, 0);
            }
        }
    }

    & when (@variationSidebarWide) {
        .ui.visible.wide.right.sidebar ~ .fixed,
        .ui.visible.wide.right.sidebar ~ .pusher {
            transform: translate3d(-@wideWidth, 0, 0);
        }

        & when (@variationSidebarVeryWide) {
            .ui.visible[class*="very wide"].right.sidebar ~ .fixed,
            .ui.visible[class*="very wide"].right.sidebar ~ .pusher {
                transform: translate3d(-@veryWideWidth, 0, 0);
            }
        }
    }
}

& when (@variationSidebarLeft) {
    & when (@variationSidebarThin) {
        .ui.visible.thin.left.sidebar ~ .fixed,
        .ui.visible.thin.left.sidebar ~ .pusher {
            transform: translate3d(@thinWidth, 0, 0);
        }

        & when (@variationSidebarVeryThin) {
            .ui.visible[class*="very thin"].left.sidebar ~ .fixed,
            .ui.visible[class*="very thin"].left.sidebar ~ .pusher {
                transform: translate3d(@veryThinWidth, 0, 0);
            }
        }
    }

    & when (@variationSidebarWide) {
        .ui.visible.wide.left.sidebar ~ .fixed,
        .ui.visible.wide.left.sidebar ~ .pusher {
            transform: translate3d(@wideWidth, 0, 0);
        }

        & when (@variationSidebarVeryWide) {
            .ui.visible[class*="very wide"].left.sidebar ~ .fixed,
            .ui.visible[class*="very wide"].left.sidebar ~ .pusher {
                transform: translate3d(@veryWideWidth, 0, 0);
            }
        }
    }
}

& .step {
    background: @circularStepColor;
    cursor: default;
    height: @circularStepBorderWidth;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    flex: 1;
    position: relative;
    margin-left: @circularStepRingSize;

    &::before {
        left: -@circularStepRingSize;
    }
    &::after {
        left: @circularStepIconDistance;
    }

    &.completed {
        background: @circularStepCompletedBackground;
    }
    &.completed::after {
        left: @circularStepCompletedIconDistance;
    }
    &:last-child {
        flex: 0;
    }
    & .content {
        margin-top: @circularStepContentMarginTop;
        padding: @circularStepContentPadding;
        &.center.aligned {
            margin-top: @circularStepContentCenterAlignedMarginTop;
            & .title {
                padding: @circularStepContentPadding;
                margin-left: @circularStepContentCenterAlignedMarginLeft;
                background: @circularStepContentCenterAlignedBackground;
            }
        }
        &.bottom.aligned {
            margin-top: @circularStepContentBottomAlignedMarginTop;
        }
        &:not(.aligned) .title + .description {
            margin-top: @circularStepContentDescriptionDistance;
        }
    }
}

& .step {
    color: inherit;

    &::before {
        content: "";
        border-radius: 50%;
        border: @circularStepBorder;
        height: @circularStepRingSize;
        width: @circularStepRingSize;
        line-height: @circularStepRingSize;
        position: absolute;
    }
    &::after {
        content: "";
        display: block;
        position: absolute;
        border-radius: 50%;
        background: @circularStepColor;
        height: @circularStepIconSize;
        width: @circularStepIconSize;
    }
    &.active {
        &::before {
            border-color: @circularStepActiveColor;
        }

        &::after {
            background: @circularStepActiveColor;
        }
        & .title {
            color: @circularStepActiveColor;
        }
    }
    &.completed {
        &::before {
            background: @circularStepCompletedBackground;
            border-color: @circularStepCompletedBackground;
        }
        &::after {
            background: transparent;
            content: "\e800";
            font-family: Step;
            color: @circularStepCompletedColor;
            height: auto;
            line-height: @circularStepCompletedIconLineHeight;
        }
    }
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.stackable.menu {
        flex-direction: column;

        &.pointing .active.item::after when (@variationMenuPointing) {
            display: none;
        }
    }
    .ui.stackable.menu .item {
        width: 100% !important;
    }
    .ui.stackable.menu .item::before {
        position: absolute;
        content: "";
        top: auto;
        bottom: 0;
        left: 0;
        width: 100%;
        height: @dividerSize;
        background: @verticalDividerBackground;
    }

    .ui.stackable.menu .left.menu,
    .ui.stackable.menu .left.item {
        margin-right: 0 !important;
    }
    .ui.stackable.menu .right.menu,
    .ui.stackable.menu .right.item {
        margin-left: 0 !important;
    }
    .ui.stackable.menu .center.menu,
    .ui.stackable.menu .center.item {
        margin-left: 0 !important;
        margin-right: 0 !important;
    }

    .ui.stackable.menu .right.menu,
    .ui.stackable.menu .center.menu,
    .ui.stackable.menu .left.menu {
        flex-direction: column;
    }
}

& when (@variationButtonSpaced) {
    .ui.spaced.buttons .ui.button {
        margin-bottom: @spacedMargin;
        margin-right: @spacedMargin;
        border-radius: @basicBorderRadius;
    }
    & when (@variationButtonBasic) {
        .ui.spaced.basic.buttons {
            border: none;
            & .button {
                border: @basicGroupBorder;
                &.basic {
                    border: none;
                }
            }
        }
        & when (@variationButtonVertical) {
            .ui.spaced.basic.vertical.buttons .button:first-child {
                border-top: @basicGroupBorder;
            }
        }
        & when (@variationButtonWrapping) {
            .ui.spaced.basic.wrapping.buttons .button@{notBasic} {
                border-top: @basicGroupBorder;
                border-right: @basicGroupBorder;
                &:first-child {
                    border-left: @basicGroupBorder;
                }
            }
        }
        & when (@variationButtonInverted) {
            .ui.spaced.basic.inverted.buttons .basic.button {
                margin-bottom: e(%("calc(%d + %d)", @spacedMargin, @basicColoredBorderSize));
                margin-top: @basicColoredBorderSize;
            }
        }
    }
}

& when (@variationModalBasic) {
    .ui.basic.modal {
        background-color: transparent;
        border: none;
        border-radius: 0;
        box-shadow: none !important;
        color: @basicModalColor;
    }
    .ui.ui.modal > .basic.header,
    .ui.ui.modal > .basic.actions,
    .ui.basic.modal > .header,
    .ui.basic.modal > .content,
    .ui.basic.modal > .actions {
        background-color: transparent;
    }
    .ui.modal > .basic.header {
        border-bottom: none;
    }
    .ui.basic.modal > .header {
        color: @basicModalHeaderColor;
        border-bottom: none;
    }
    & when (@variationModalClose) {
        .ui.basic.modal > .close {
            top: @basicModalCloseTop;
            right: @basicModalCloseRight;
            color: @basicInnerCloseColor;
        }
    }
    .ui.inverted.dimmer > .basic.modal {
        color: @basicInvertedModalColor;
    }
    .ui.inverted.dimmer > .ui.basic.modal > .header {
        color: @basicInvertedModalHeaderColor;
    }
}

@media (max-width: 992px) {
  .post-list-container {
    .post-inner {
      min-width: 0;
      width: 100%;
      margin-top: 16px;

      .post {
        margin: 12px 16px 12px 16px;
        padding: 18px 22px 18px 22px;

        .post-left {
          .post-title {
            font-size: 17px;
            font-weight: bold;
          }

          .post-abstract {
            margin-top: 10px;
          }

          .post-info {
            margin-top: 10px;

            .post-time {
              font-size: 12px;
            }

            .post-tag {
              font-size: 12px;
              margin-left: 10px;
            }
          }
        }

        .post-feature-image {
          width: 0;
          height: 0;
          flex-basis: 0;
          flex-shrink: 0;
          margin-left: 0;
          border-radius: 2px;
          overflow: hidden;
          background-size: cover;
          background-position: center;
        }
      }
    }
  }
}

&-panel{
    &-icon-btn{
        display: inline-block;
        width: 20px;
        height: 24px;
        line-height: 26px;
        margin-top: 4px;
        text-align: center;
        cursor: pointer;
        color: @btn-disable-color;
        transition: color @transition-time @ease-in-out;
        &:hover{
            color: @primary-color;
        }
        i{
            font-size: 14px;
        }
    }

    &-body-wrapper&-with-sidebar{
        padding-left: 92px;
    }
    &-sidebar{
        width: 92px;
        float: left;
        margin-left: -92px;
        position: absolute;
        top: 0;
        bottom: 0;
        background: @table-thead-bg;
        border-right: 1px solid @border-color-split;
        border-radius: @border-radius-small 0 0 @border-radius-small;
        overflow: auto;
    }
    &-shortcut{
        padding: @btn-padding-large;
        transition: all @transition-time @ease-in-out;
        cursor: pointer;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;

        &:hover{
            background: @border-color-split;
        }
    }
    &-body{
        float: left;
    }
}

&-list{
    margin-top: 8px;

    &-file{
        padding: 4px;
        color: @text-color;
        border-radius: @border-radius-small;
        transition: background-color @transition-time @ease-in-out;
        overflow: hidden;
        position: relative;

        & > span{
            cursor: pointer;
            transition: color @transition-time @ease-in-out;
            i{
                display: inline-block;
                width: @font-size-small;
                height: @font-size-small;
                color: @text-color;
                text-align: center;
            }
        }

        &:hover{
            background: @input-disabled-bg;
            & > span{
                color: @primary-color;
                i{
                    color: @text-color;
                }
            }
            .@{upload-prefix-cls}-list-remove{
                opacity: 1;
            }
        }
    }
    &-remove{
        opacity: 0;
        font-size: 18px;
        cursor: pointer;
        float: right;
        margin-right: 4px;
        color: @legend-color;
        transition: all @transition-time ease;
        &:hover{
            color: #444;
        }
    }
}

&-filter{
    display: inline-block;
    cursor: pointer;
    position: relative;
    //top: 1px;

    i{
        color: @btn-disable-color;
        transition: color @transition-time @ease-in-out;
        &:hover{
            color: inherit;
        }
        &.on{
            color: @primary-color;
        }
    }
    &-list{
        padding: 8px 0 0;
        &-item{
            padding: 0 12px 8px;

            .ivu-checkbox-wrapper + .ivu-checkbox-wrapper{
                margin: 0;
            }
            label {
                display: block;

                & > span{
                    margin-right: 4px;
                }
            }
        }
        ul{
            padding-bottom: 8px;
        }
        .select-item(@table-prefix-cls, @table-select-item-prefix-cls);
    }
    &-footer{
        padding: 4px;
        border-top: 1px solid @border-color-split;
        overflow: hidden;
        button:first-child{
            float: left;
        }
        button:last-child{
            float: right;
        }
    }
}

&-status {
    line-height: inherit;
    vertical-align: baseline;

    &-dot {
        width: 6px;
        height: 6px;
        display: inline-block;
        border-radius: 50%;
        vertical-align: middle;
        position: relative;
        top: -1px;
    }
    &-success {
        background-color: @success-color;
    }
    &-processing {
        background-color: @processing-color;
        position: relative;
        &:after {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            border-radius: 50%;
            border: 1px solid @processing-color;
            content: '';
            animation: aniStatusProcessing 1.2s infinite ease-in-out;
        }
    }
    &-default {
        background-color: @normal-color;
    }
    &-error {
        background-color: @error-color;
    }
    &-warning {
        background-color: @warning-color;
    }
    &-text {
        display: inline-block;
        color: @text-color;
        font-size: @font-size-small;
        margin-left: 6px;
    }
}

&-item {
    display: inline-block;
    //float: left;
    vertical-align: middle;
    min-width: @btn-circle-size;
    height: @btn-circle-size;
    line-height: @btn-circle-size - 2px;
    margin-right: 4px;
    text-align: center;
    list-style: none;
    background-color: #fff;
    user-select: none;
    cursor: pointer;
    font-family: Arial;
    font-weight: 500;
    border: 1px solid @border-color-base;
    border-radius: @btn-border-radius;
    //transition: all @transition-time @ease-in-out;
    transition: border @transition-time @ease-in-out, color @transition-time @ease-in-out;

    a {
        font-family: "Monospaced Number";
        margin: 0 6px;
        text-decoration: none;
        color: @text-color;
        //transition: none;
    }

    &:hover {
        border-color: @primary-color;
        a {
            color: @primary-color;
        }
    }

    &-active {
        border-color: @primary-color;

        a, &:hover a {
            color: @primary-color;
        }
    }
}

&-search{
    cursor: pointer;
    padding: 0 16px !important;
    background: @primary-color !important;
    color: #fff !important;
    border-color: @primary-color !important;
    transition: all @transition-time @ease-in-out;
    position: relative;
    z-index: 2;

    i{
        font-size: 16px;
    }

    &:hover{
        background: tint(@primary-color, 20%) !important;
        border-color: tint(@primary-color, 20%) !important;
    }
    &:active{
        background: shade(@primary-color, 5%) !important;
        border-color: shade(@primary-color, 5%) !important;
    }

    &-icon{
        cursor: pointer;
        transition: color @transition-time @ease-in-out;
        &:hover{
            color: inherit;
        }
    }

    &:before{
        content: '';
        display: block;
        width: 1px;
        position: absolute;
        top: -1px;
        bottom: -1px;
        left: -1px;
        background: inherit;
    }
}
